import React, { Component } from 'react';
import styles from './style.scss';
import { getProxyToUrl } from '../../../app/fetch';

const BADGE_BASE_URL = 'https://media.retroachievements.org/Badge/';
const HOLD_MS = 5000;
const FADE_MS = 400;

const CHIME_SRC = 'data:audio/mpeg;base64,';
let _audioCtx = null;

function initChime() {
  if (_audioCtx) return;
  try {
    _audioCtx = new (window.AudioContext || window.webkitAudioContext)();
    // Unlock the context on first user interaction (browser autoplay policy)
    const unlock = () => {
      if (_audioCtx && _audioCtx.state === 'suspended') {
        _audioCtx.resume().catch(() => {});
      }
    };
    const el = document.documentElement;
    el.addEventListener('keydown', unlock);
    el.addEventListener('mousedown', unlock);
    el.addEventListener('touchstart', unlock, { passive: true });
  } catch (e) {
    _audioCtx = null;
  }
}

function playChime() {
  if (!_audioCtx) return;
  try {
    const synth = () => {
      const ctx = _audioCtx;
      // Ascending 4-note achievement jingle: C5 E5 G5 C6
      const notes = [523.25, 659.25, 783.99, 1046.50];
      const master = ctx.createGain();
      master.gain.value = 0.7;
      master.connect(ctx.destination);
      notes.forEach((freq, i) => {
        const t = ctx.currentTime + i * 0.13;
        const osc = ctx.createOscillator();
        const gain = ctx.createGain();
        osc.type = 'sine';
        osc.frequency.value = freq;
        osc.connect(gain);
        gain.connect(master);
        gain.gain.setValueAtTime(0, t);
        gain.gain.linearRampToValueAtTime(0.9, t + 0.015);
        gain.gain.exponentialRampToValueAtTime(0.001, t + 0.65);
        osc.start(t);
        osc.stop(t + 0.65);
      });
    };
    if (_audioCtx.state === 'suspended') {
      _audioCtx.resume().then(synth).catch(() => {});
    } else {
      synth();
    }
  } catch (e) {}
}


let _instance = null;

export function showAchievement(title, subtitle, badge) {
  if (_instance) {
    _instance.enqueue(title, subtitle, badge, 'achievement');
  }
}

export function showMastery(gameTitle, gameBadge, totalCount, totalPoints, username, gameTags) {
  if (_instance) {
    const subtitle = `${totalCount} achievement${totalCount !== 1 ? 's' : ''}, ${totalPoints} points`;
    _instance.enqueue(gameTitle, subtitle, gameBadge, 'mastery', username, gameTags);
  }
}

export class AchievementToast extends Component {
  constructor(props) {
    super(props);
    this.state = {
      current: null,
      phase: null,  // 'show' | 'hide' | null
    };
    this.queue = [];
    this.timer = null;
  }

  componentDidMount() {
    _instance = this;
    initChime();
  }

  componentWillUnmount() {
    _instance = null;
    if (this.timer) clearTimeout(this.timer);
  }

  enqueue(title, subtitle, badge, type = 'achievement', username = null, gameTags = []) {
    this.queue.push({ title, subtitle, badge, type, username, gameTags });
    if (!this.state.current) {
      this.showNext();
    }
  }

  showNext() {
    if (this.queue.length === 0) {
      this.setState({ current: null, phase: null });
      return;
    }
    const next = this.queue.shift();
    this.setState({ current: next, phase: 'show' });
    playChime();
    this.timer = setTimeout(() => {
      this.setState({ phase: 'hide' });
      this.timer = setTimeout(() => {
        this.showNext();
      }, FADE_MS);
    }, HOLD_MS);
  }

  render() {
    const { current, phase } = this.state;
    if (!current || !phase) return null;

    const { title, subtitle, badge, type, username, gameTags } = current;
    const isMastery = type === 'mastery';
    const badgeUrl = badge
      ? getProxyToUrl(isMastery
          ? `https://media.retroachievements.org/Images/${badge}`
          : `${BADGE_BASE_URL}${badge}.png`)
      : null;
    const avatarUrl = (isMastery && username)
      ? getProxyToUrl(`https://media.retroachievements.org/UserPic/${username}.png`)
      : null;

    return (
      <div className={`${styles['achievement-toast']} ${isMastery ? styles['achievement-toast--mastery'] : ''} ${styles[phase]}`}>
        {badgeUrl && (
          <img
            className={styles['achievement-toast__badge']}
            src={badgeUrl}
            alt=""
          />
        )}
        <div className={styles['achievement-toast__text']}>
          <span className={styles['achievement-toast__header']}>{isMastery ? 'Completed' : 'Achievement Unlocked'}</span>
          <span className={styles['achievement-toast__title']}>{title}</span>
          {isMastery && gameTags && gameTags.length > 0 && (
            <div className={styles['achievement-toast__tags']}>
              {gameTags.map(tag => (
                <span key={tag} className={styles['achievement-toast__tag']}>{tag}</span>
              ))}
            </div>
          )}
          {subtitle && (
            <span className={styles['achievement-toast__subtitle']}>{subtitle}</span>
          )}
        </div>
        {isMastery && username && (
          <div className={styles['achievement-toast__user']}>
            {avatarUrl && (
              <img className={styles['achievement-toast__avatar']} src={avatarUrl} alt="" />
            )}
            <span className={styles['achievement-toast__username']}>{username}</span>
          </div>
        )}
      </div>
    );
  }
}
